// TestRegression_MultiDeviceU2FAuthenticationChallenge tests that when a user
// has registered multiple U2F hardware tokens, the authentication challenge
// includes all of them, not just one. This is a regression test for a bug where
// users with multiple U2F devices could only use one of them during login.
func TestRegression_MultiDeviceU2FAuthenticationChallenge(t *testing.T) {
	ctx := context.Background()
	clock := clockwork.NewFakeClock()

	// Create a test auth server with U2F enabled
	as, err := auth.NewTestAuthServer(auth.TestAuthServerConfig{
		Dir:   t.TempDir(),
		Clock: clock,
	})
	require.NoError(t, err)
	defer as.Close()

	srv, err := as.NewTestTLSServer()
	require.NoError(t, err)
	defer srv.Close()

	// Enable U2F support
	authPref, err := services.NewAuthPreference(types.AuthPreferenceSpecV2{
		Type: teleport.Local,
		U2F: &types.U2F{
			AppID:  "teleport",
			Facets: []string{"teleport"},
		},
	})
	require.NoError(t, err)
	err = as.AuthServer.SetAuthPreference(authPref)
	require.NoError(t, err)

	// Create a test user
	user, _, err := auth.CreateUserAndRole(as.AuthServer, "test-user", []string{"role"})
	require.NoError(t, err)

	// Create a client for the user
	cl, err := srv.NewClient(auth.TestUser(user.GetName()))
	require.NoError(t, err)

	// Register first U2F device
	firstDevice := registerU2FDevice(t, ctx, cl, "u2f-device-1", clock)
	clock.Advance(30 * time.Second)

	// Register second U2F device
	secondDevice := registerU2FDevice(t, ctx, cl, "u2f-device-2", clock)
	clock.Advance(30 * time.Second)

	// Register third U2F device
	thirdDevice := registerU2FDevice(t, ctx, cl, "u2f-device-3", clock)
	clock.Advance(30 * time.Second)

	// Get all MFA devices to confirm they're all registered
	devicesResp, err := cl.GetMFADevices(ctx, &proto.GetMFADevicesRequest{})
	require.NoError(t, err)
	require.Equal(t, 3, len(devicesResp.Devices), "expected 3 registered U2F devices")

	// TEST 1: Get U2F sign request and verify it contains ALL registered devices
	t.Run("multi-device U2F challenge contains all devices", func(t *testing.T) {
		signRequest, err := as.AuthServer.U2FSignRequest(user.GetName(), []byte("password"))
		require.NoError(t, err)

		// The challenge should contain all 3 devices
		require.Equal(t, 3, len(signRequest.Challenges),
			"Expected 3 U2F challenges (one for each device), but got %d. "+
				"This indicates the multi-device U2F bug where only one device's challenge is sent.",
			len(signRequest.Challenges))

		// Verify each challenge has the correct key handle
		keyHandlesInChallenge := make(map[string]bool)
		for _, challenge := range signRequest.Challenges {
			keyHandlesInChallenge[challenge.KeyHandle] = true
		}

		// Get expected key handles from registered devices
		expectedKeyHandles := map[string]bool{
			firstDevice.GetU2F().KeyHandle:  false,
			secondDevice.GetU2F().KeyHandle: false,
			thirdDevice.GetU2F().KeyHandle:  false,
		}

		// Check all key handles are present
		for expectedKH := range expectedKeyHandles {
			require.True(t, keyHandlesInChallenge[expectedKH],
				"Expected key handle %s not found in challenge. Bug: not all devices' challenges sent.", expectedKH)
		}

		// Verify backward compatibility: AuthenticateChallenge (old format) should contain first device
		require.NotNil(t, signRequest.AuthenticateChallenge,
			"AuthenticateChallenge should not be nil for backward compatibility")
		require.Equal(t, signRequest.AuthenticateChallenge.KeyHandle, firstDevice.GetU2F().KeyHandle,
			"Backward compatibility: AuthenticateChallenge should contain first device")
	})

	// TEST 2: Test JSON marshaling/unmarshaling of U2FAuthenticateChallenge
	// This tests client/server version compatibility
	t.Run("U2F challenge JSON marshaling with multiple devices", func(t *testing.T) {
		signRequest, err := as.AuthServer.U2FSignRequest(user.GetName(), []byte("password"))
		require.NoError(t, err)

		// Marshal to JSON
		jsonBytes, err := json.Marshal(signRequest)
		require.NoError(t, err)

		// Unmarshal back
		var unmarshaled auth.U2FAuthenticateChallenge
		err = json.Unmarshal(jsonBytes, &unmarshaled)
		require.NoError(t, err)

		// Verify all challenges are preserved through JSON marshaling/unmarshaling
		require.Equal(t, 3, len(unmarshaled.Challenges),
			"JSON marshaling/unmarshaling lost challenges. Expected 3, got %d", len(unmarshaled.Challenges))

		// Verify challenge contents match
		require.Empty(t, cmp.Diff(signRequest.Challenges, unmarshaled.Challenges),
			"Challenge data mismatch after JSON round-trip")
	})

	// TEST 3: Simulate old client (pre-6.0) with new server
	// Old clients should still work by using AuthenticateChallenge field
	t.Run("backward compatibility with old client receiving new server response", func(t *testing.T) {
		signRequest, err := as.AuthServer.U2FSignRequest(user.GetName(), []byte("password"))
		require.NoError(t, err)

		// Simulate old client unmarshaling
		// Old clients only know about the single embedded AuthenticateChallenge field
		var oldClientView struct {
			Challenge string `json:"challenge"`
			KeyHandle string `json:"keyHandle"`
			AppID     string `json:"appId"`
			Version   string `json:"version"`
		}

		jsonBytes, err := json.Marshal(signRequest)
		require.NoError(t, err)

		err = json.Unmarshal(jsonBytes, &oldClientView)
		require.NoError(t, err)

		// Old client should at least get the first device's challenge
		require.NotEmpty(t, oldClientView.Challenge, "old client should receive at least one challenge")
		require.NotEmpty(t, oldClientView.KeyHandle, "old client should receive at least one key handle")
	})

	// TEST 4: Verify adding/removing devices maintains multi-device challenges
	t.Run("multi-device challenges after device deletion", func(t *testing.T) {
		// Delete one device
		deleteStream, err := cl.DeleteMFADevice(ctx)
		require.NoError(t, err)

		err = deleteStream.Send(&proto.DeleteMFADeviceRequest{
			Request: &proto.DeleteMFADeviceRequest_Init{
				Init: &proto.DeleteMFADeviceRequestInit{
					DeviceName: secondDevice.GetName(),
				},
			},
		})
		require.NoError(t, err)

		// Receive auth challenge and respond with first device
		authChallenge, err := deleteStream.Recv()
		require.NoError(t, err)

		// Should have challenges for remaining 2 devices
		require.Equal(t, 2, len(authChallenge.GetMFAChallenge().U2F),
			"After deleting one device, expected 2 U2F challenges, got %d", len(authChallenge.GetMFAChallenge().U2F))

		// Authenticate with first device
		sigReq := &u2f.AuthenticateChallenge{
			Challenge: authChallenge.GetMFAChallenge().U2F[0].Challenge,
			KeyHandle: authChallenge.GetMFAChallenge().U2F[0].KeyHandle,
			AppID:     authChallenge.GetMFAChallenge().U2F[0].AppID,
		}

		// This is a simplified test - in real scenario, would get actual signature from U2F device
		// For now, just verify the structure is correct
		require.NotEmpty(t, sigReq.Challenge)
		require.NotEmpty(t, sigReq.KeyHandle)
	})

	// TEST 5: Verify mfaAuthChallenge function returns all devices
	t.Run("mfaAuthChallenge returns all U2F devices", func(t *testing.T) {
		// Re-register the device for this test
		registerU2FDevice(t, ctx, cl, "u2f-device-4", clock)

		challenge, err := as.AuthServer.MFAAuthChallenge(ctx, user.GetName(), &proto.MFAAuthenticateChallenge{})
		require.NoError(t, err)

		// Count U2F devices in challenge
		u2fCount := len(challenge.U2F)

		// Should have at least 3 devices (we registered 3, deleted 1, so should have at least 3 or 4 depending on test order)
		require.GreaterOrEqual(t, u2fCount, 2,
			"mfaAuthChallenge should return challenges for all registered U2F devices, got %d", u2fCount)
	})
}

// TestRegression_ClientServerVersionCompatibility tests that older clients can
// still authenticate when the server sends multi-device U2F challenges.
func TestRegression_ClientServerVersionCompatibility(t *testing.T) {
	ctx := context.Background()
	clock := clockwork.NewFakeClock()

	// Create a test auth server
	as, err := auth.NewTestAuthServer(auth.TestAuthServerConfig{
		Dir:   t.TempDir(),
		Clock: clock,
	})
	require.NoError(t, err)
	defer as.Close()

	srv, err := as.NewTestTLSServer()
	require.NoError(t, err)
	defer srv.Close()

	// Enable U2F support
	authPref, err := services.NewAuthPreference(types.AuthPreferenceSpecV2{
		Type: teleport.Local,
		U2F: &types.U2F{
			AppID:  "teleport",
			Facets: []string{"teleport"},
		},
	})
	require.NoError(t, err)
	err = as.AuthServer.SetAuthPreference(authPref)
	require.NoError(t, err)

	// Create a test user
	user, _, err := auth.CreateUserAndRole(as.AuthServer, "test-user", []string{"role"})
	require.NoError(t, err)

	// Create a client for the user
	cl, err := srv.NewClient(auth.TestUser(user.GetName()))
	require.NoError(t, err)

	// Register two U2F devices
	registerU2FDevice(t, ctx, cl, "u2f-device-1", clock)
	clock.Advance(30 * time.Second)
	registerU2FDevice(t, ctx, cl, "u2f-device-2", clock)

	t.Run("new server sends challenges in backward compatible format", func(t *testing.T) {
		signRequest, err := as.AuthServer.U2FSignRequest(user.GetName(), []byte("password"))
		require.NoError(t, err)

		// Verify the response has both old and new formats
		require.NotNil(t, signRequest.AuthenticateChallenge,
			"Old format (AuthenticateChallenge) should be present for backward compatibility")
		require.Equal(t, 2, len(signRequest.Challenges),
			"New format (Challenges) should contain all registered devices")

		// The old format should have the first device's challenge
		require.NotEmpty(t, signRequest.AuthenticateChallenge.Challenge)
		require.NotEmpty(t, signRequest.AuthenticateChallenge.KeyHandle)

		// Verify old-style client can still parse the response
		jsonBytes, err := json.Marshal(signRequest)
		require.NoError(t, err)

		// Simulate old client unmarshaling to the simple struct
		var oldFormat auth.U2FAuthenticateChallenge
		err = json.Unmarshal(jsonBytes, &oldFormat)
		require.NoError(t, err)

		// Verify the old format fields are still populated
		require.NotNil(t, oldFormat.AuthenticateChallenge)
		require.NotEmpty(t, oldFormat.AuthenticateChallenge.Challenge)
	})

	t.Run("U2FAuthenticateChallenge struct compatibility", func(t *testing.T) {
		// Test the compatibility struct's JSON marshaling
		test1Challenge := &auth.U2FAuthenticateChallenge{
			AuthenticateChallenge: &u2f.AuthenticateChallenge{
				Challenge: "c1",
				KeyHandle: "kh1",
				AppID:     "app1",
			},
			Challenges: []u2f.AuthenticateChallenge{
				{Challenge: "c1", KeyHandle: "kh1", AppID: "app1"},
				{Challenge: "c2", KeyHandle: "kh2", AppID: "app1"},
				{Challenge: "c3", KeyHandle: "kh3", AppID: "app1"},
			},
		}

		// Marshal to JSON
		jsonBytes, err := json.Marshal(test1Challenge)
		require.NoError(t, err)

		// Verify JSON contains the challenges field
		var jsonMap map[string]interface{}
		err = json.Unmarshal(jsonBytes, &jsonMap)
		require.NoError(t, err)

		// Challenges field must be present in JSON
		require.NotNil(t, jsonMap["challenges"],
			"Challenges field missing from JSON. This indicates a marshaling bug.")

		challengesVal, ok := jsonMap["challenges"].([]interface{})
		require.True(t, ok, "Challenges should be an array")
		require.Equal(t, 3, len(challengesVal),
			"All 3 challenges should be in the JSON response, got %d", len(challengesVal))

		// Unmarshal back and verify
		var unmarshaled auth.U2FAuthenticateChallenge
		err = json.Unmarshal(jsonBytes, &unmarshaled)
		require.NoError(t, err)

		require.Equal(t, 3, len(unmarshaled.Challenges),
			"After unmarshal, should have 3 challenges")

		// Verify old format is still there
		require.NotNil(t, unmarshaled.AuthenticateChallenge)
		require.Equal(t, "c1", unmarshaled.AuthenticateChallenge.Challenge)
		require.Equal(t, "kh1", unmarshaled.AuthenticateChallenge.KeyHandle)
	})
}

// registerU2FDevice is a helper to register a U2F device for a user
func registerU2FDevice(t *testing.T, ctx context.Context, cl *auth.Client, deviceName string, clock clockwork.FakeClock) *types.MFADevice {
	addStream, err := cl.AddMFADevice(ctx)
	require.NoError(t, err)

	err = addStream.Send(&proto.AddMFADeviceRequest{
		Request: &proto.AddMFADeviceRequest_Init{
			Init: &proto.AddMFADeviceRequestInit{
				DeviceName: deviceName,
				Type:       proto.AddMFADeviceRequestInit_U2F,
			},
		},
	})
	require.NoError(t, err)

	// Get auth challenge
	authChallenge, err := addStream.Recv()
	require.NoError(t, err)

	// Respond to auth challenge (no MFA devices yet, so empty response)
	err = addStream.Send(&proto.AddMFADeviceRequest{
		Request: &proto.AddMFADeviceRequest_ExistingMFAResponse{
			ExistingMFAResponse: &proto.MFAAuthenticateResponse{},
		},
	})
	require.NoError(t, err)

	// Get registration challenge
	registerChallenge, err := addStream.Recv()
	require.NoError(t, err)

	u2fRegisterChallenge := registerChallenge.GetNewMFARegisterChallenge().GetU2F()
	require.NotNil(t, u2fRegisterChallenge)

	// Create a mock U2F device and get its response
	mdev, err := mocku2f.Create()
	require.NoError(t, err)

	mresp, err := mdev.RegisterResponse(&u2f.RegisterChallenge{
		Challenge: u2fRegisterChallenge.Challenge,
		AppID:     u2fRegisterChallenge.AppID,
	})
	require.NoError(t, err)

	// Send registration response
	err = addStream.Send(&proto.AddMFADeviceRequest{
		Request: &proto.AddMFADeviceRequest_NewMFARegisterResponse{
			NewMFARegisterResponse: &proto.MFARegisterResponse{
				Response: &proto.MFARegisterResponse_U2F{
					U2F: &proto.U2FRegisterResponse{
						RegistrationData: mresp.RegistrationData,
						ClientData:       mresp.ClientData,
					},
				},
			},
		},
	})
	require.NoError(t, err)

	// Get acknowledgement
	registerAck, err := addStream.Recv()
	require.NoError(t, err)
	require.NoError(t, addStream.CloseSend())

	device := registerAck.GetAck().Device
	require.NotNil(t, device)
	require.Equal(t, device.GetName(), deviceName)

	return device
}

